insert into public.resources ("id", "client_id", "title", "type", "category", "content", "external_link", "tags", "created_at", "updated_at") values
  ('r-1', 'c-universal', 'Guía de tono y voz — Universal Solutions', 'referencia', 'cliente', 'Tono cercano, educativo y confiable. Hablar de ''tu familia'' y ''tu tranquilidad''. Evitar tecnicismos de seguros sin explicarlos. Siempre cerrar con CTA a WhatsApp.', '', '["branding","tono","universal"]'::jsonb, '2026-02-01', '2026-05-10'),
  ('r-2', null, 'Plantilla de reporte mensual', 'plantilla', 'estrategia', 'Estructura: 1) Resumen ejecutivo, 2) Métricas clave vs mes anterior, 3) Contenido top, 4) Aprendizajes, 5) Plan del próximo mes.', 'https://docs.google.com', '["reporte","plantilla","mensual"]'::jsonb, '2026-01-15', '2026-04-02'),
  ('r-3', null, 'Checklist de publicación', 'sop', 'contenido', '1. Copy revisado y sin errores. 2. Pieza aprobada por el cliente. 3. Hashtags según guía. 4. CTA claro. 5. Programada en horario óptimo. 6. Registrada en el calendario de Flare OS.', '', '["checklist","publicacion"]'::jsonb, '2026-03-01', '2026-03-01'),
  ('r-4', 'c-autozone', 'Banco de fotos de tienda Autozone', 'link', 'contenido', 'Carpeta con fotos aprobadas de tienda, productos y equipo.', 'https://drive.google.com', '["fotos","autozone"]'::jsonb, '2026-04-10', '2026-06-01'),
  ('r-5', null, 'Script de venta para prospectos', 'script', 'ventas', 'Apertura: diagnóstico gratuito de redes. Desarrollo: mostrar caso similar. Cierre: propuesta con 2 opciones de alcance.', '', '["ventas","prospectos"]'::jsonb, '2026-02-20', '2026-05-18');
insert into public.prompts ("id", "client_id", "title", "category", "prompt_content", "recommended_use", "required_variables", "tags", "created_at", "updated_at") values
  ('p-1', 'c-universal', 'Generador de carruseles educativos de seguros', 'contenido', 'Actúa como copywriter experto en seguros para la comunidad latina en USA. Crea un carrusel de {num_slides} slides sobre {tema}. Tono cercano y educativo. Slide 1: gancho fuerte. Slides intermedios: un punto por slide con ejemplo cotidiano. Último slide: CTA a WhatsApp. Marca: Universal Solutions.', 'Usar para generar borradores de carruseles educativos. Revisar siempre datos legales con el cliente.', '["num_slides","tema"]'::jsonb, '["carrusel","seguros","universal"]'::jsonb, '2026-03-05', '2026-05-22'),
  ('p-2', null, 'Guionista de reels con gancho', 'contenido', 'Actúa como guionista de reels virales. Escribe un guion de máximo {duracion} segundos sobre {tema} para la marca {marca}. Estructura: gancho en los primeros 2 segundos, desarrollo con 3 puntos rápidos, CTA final a {cta}. Lenguaje hablado, frases cortas.', 'Base para cualquier reel de cliente. Ajustar tono según la guía de marca.', '["duracion","tema","marca","cta"]'::jsonb, '["reel","guion","general"]'::jsonb, '2026-02-10', '2026-04-15'),
  ('p-3', null, 'Analista de métricas mensuales', 'estrategia', 'Actúa como estratega de redes sociales. Con estas métricas del mes: {metricas}, y las del mes anterior: {metricas_anteriores}, escribe un análisis de rendimiento con: 3 hallazgos clave, 2 alertas y 3 recomendaciones accionables para el próximo mes.', 'Usar al preparar reportes mensuales de cualquier cliente.', '["metricas","metricas_anteriores"]'::jsonb, '["metricas","reporte","analisis"]'::jsonb, '2026-03-20', '2026-03-20'),
  ('p-4', 'c-ochopilates', 'Ideas de contenido para estudio de pilates', 'contenido', 'Actúa como creador de contenido fitness. Genera {cantidad} ideas de contenido para un estudio boutique de pilates dirigido a mujeres 25-45. Mezcla: educación postural, comunidad, testimonios y promociones. Para cada idea: título, formato sugerido y gancho.', 'Brainstorming mensual si se cierra el contrato con Ocho Pilates.', '["cantidad"]'::jsonb, '["pilates","ideas","fitness"]'::jsonb, '2026-06-01', '2026-06-01');
insert into public.processes ("id", "client_id", "title", "area", "description", "steps", "responsible", "frequency", "status", "created_at", "updated_at") values
  ('pr-1', null, 'Onboarding de cliente nuevo', 'estrategia', 'Proceso estándar para arrancar con un cliente nuevo en máximo 2 semanas.', '["Reunión kickoff: objetivos, audiencia y expectativas","Recolección de accesos y material de marca","Auditoría de redes y competencia","Definición de estrategia y pilares de contenido","Creación del cliente en Flare OS con objetivos y KPIs","Primer calendario editorial aprobado"]'::jsonb, 'Juan', 'Por cliente nuevo', 'activo', '2026-01-10', '2026-04-01'),
  ('pr-2', null, 'Producción de carrusel', 'contenido', 'Flujo de producción de un carrusel desde idea hasta publicación.', '["Idea validada con cliente asociado en Flare OS","Redacción de copy por slide","Diseño en Figma con plantilla de marca","Revisión interna de calidad","Aprobación del cliente","Programación y registro en calendario"]'::jsonb, 'Sara', 'Por pieza', 'activo', '2026-01-20', '2026-03-12'),
  ('pr-3', null, 'Producción de reels', 'contenido', 'Flujo de producción de reels: guion, grabación, edición y entrega.', '["Guion con gancho aprobado","Plan de grabación (locación, props, talento)","Grabación","Edición con subtítulos y música","Revisión del cliente","Programación"]'::jsonb, 'Andrés', 'Por pieza', 'activo', '2026-02-01', '2026-05-05'),
  ('pr-4', null, 'Reporte mensual de resultados', 'estrategia', 'Entrega de reporte mensual a cada cliente activo.', '["Registrar métricas del mes en Flare OS","Comparar contra mes anterior y objetivos","Redactar hallazgos y recomendaciones","Armar presentación con plantilla","Agendar y presentar al cliente","Registrar próxima acción en la ficha del cliente"]'::jsonb, 'Juan', 'Mensual', 'activo', '2026-01-25', '2026-04-20'),
  ('pr-5', 'c-autozone', 'Proceso de pauta Autozone', 'pauta', 'Flujo de campañas de pauta mensual para Autozone.', '["Confirmar promo y presupuesto del mes","Diseñar piezas de anuncio","Montar campaña en Meta Ads","Optimización semanal","Reporte de resultados de pauta"]'::jsonb, 'Laura', 'Mensual', 'borrador', '2026-05-15', '2026-06-01');
